                alt={`CCTV Frame ${selectedCCTV.name}`}
                className="w-full h-full object-cover mix-blend-screen opacity-90 filter contrast-125 saturate-50 sepia-[.3] hue-rotate-[-30deg]"
                crossOrigin="anonymous"
                onError={(e) => {
