         useAppStore.getState().setSatelliteScreenPos(null);
      }

      // 3. CCTV Screen Tracking
      const selectedCCTV = useAppStore.getState().selectedCCTV;
      let cctvPos = null;
      if (selectedCCTV && cctvDataSourceRef.current) {
